('Xiaomi Pad 6', 'xiaomi-pad-6', 'Xiaomi Pad 6 with 11" 2.8K 144Hz display, Snapdragon 870, quad speakers with Dolby Atmos, 8840mAh battery, and optional keyboard/stylus support for productivity.', 'b174577b-c696-4bb6-b0e9-a2e247ad3ad2', 'Xiaomi', 26999, 35099, '[{"url":"https://images.unsplash.com/photo-1544244015-0df4b3ffc6b0?w=800&h=800&fit=crop","alt":"Xiaomi Pad 6"},{"url":"https://images.unsplash.com/photo-1585790050230-5dd28404ccb9?w=800&h=800&fit=crop","alt":"Tablet with keyboard"},{"url":"https://images.unsplash.com/photo-1561154464-82e9aeb32f81?w=800&h=800&fit=crop","alt":"Tablet display"}]'::jsonb, '[{"sku":"XP6-GRV-6","size":"6GB/128GB","color":"Gravity Gray","colorHex":"#4A4A4A","stock":20,"price":26999},{"sku":"XP6-BLU-6","size":"6GB/128GB","color":"Mist Blue","colorHex":"#6B9AC4","stock":15,"price":26999},{"sku":"XP6-GLD-8","size":"8GB/256GB","color":"Champagne Gold","colorHex":"#F7E7CE","stock":10,"price":30999}]'::jsonb, 45, 4.5, 189, ARRAY['11" 2.8K Display', '144Hz Refresh Rate', 'Snapdragon 870', 'Dolby Atmos Quad Speakers', '8840mAh Battery', '33W Fast Charging', 'Stylus Support', 'MIUI Pad 14'], true),

('JBL Flip 6 Portable Speaker', 'jbl-flip-6', 'JBL Flip 6 portable Bluetooth speaker with powerful JBL Original Pro Sound, bold design, and IP67 waterproof and dustproof rating. 12 hours of playtime with PartyBoost for pairing multiple speakers.', 'b174577b-c696-4bb6-b0e9-a2e247ad3ad2', 'JBL', 9999, 12999, '[{"url":"https://images.unsplash.com/photo-1608043152269-423dbba4e7e1?w=800&h=800&fit=crop","alt":"JBL Flip 6 Speaker"},{"url":"https://images.unsplash.com/photo-1589003077984-894e133dabab?w=800&h=800&fit=crop","alt":"Bluetooth speaker outdoor"},{"url":"https://images.unsplash.com/photo-1558089687-f282ffcbc126?w=800&h=800&fit=crop","alt":"Speaker party setup"}]'::jsonb, '[{"sku":"JBL-BLK","size":"One Size","color":"Black","colorHex":"#000000","stock":25,"price":9999},{"sku":"JBL-RED","size":"One Size","color":"Red","colorHex":"#FF0000","stock":18,"price":9999},{"sku":"JBL-BLU","size":"One Size","color":"Blue","colorHex":"#0000FF","stock":20,"price":9999}]'::jsonb, 63, 4.6, 312, ARRAY['JBL Pro Sound', 'IP67 Waterproof', '12 Hours Playtime', 'PartyBoost', 'Bluetooth 5.1', 'USB-C Charging', 'Weight: 550g', 'Driver: Racetrack'], true);

-- New Clothing (3)
INSERT INTO products (name, slug, description, category_id, brand, price, compare_at_price, images, variants, total_stock, rating_average, rating_count, tags, is_active) VALUES
('H&M Oversized Hoodie', 'hm-oversized-hoodie', 'H&M relaxed-fit oversized hoodie in soft cotton-blend sweatshirt fabric. Drawstring jersey-lined hood, kangaroo pocket, ribbed cuffs and hem. Perfect for layering or casual streetwear looks.', 'bf01b5fb-4d88-4687-b80a-1cfc9f94051d', 'H&M', 1499, 1949, '[{"url":"https://images.unsplash.com/photo-1556821840-3a63f95609a7?w=800&h=800&fit=crop","alt":"Oversized Hoodie"},{"url":"https://images.unsplash.com/photo-1578768079470-62a9c50e8c92?w=800&h=800&fit=crop","alt":"Hoodie detail"},{"url":"https://images.unsplash.com/photo-1515886657613-9f3515b0c78f?w=800&h=800&fit=crop","alt":"Hoodie styled"}]'::jsonb, '[{"sku":"HM-HOD-BLK-M","size":"M","color":"Black","colorHex":"#000000","stock":20,"price":1499},{"sku":"HM-HOD-GRY-L","size":"L","color":"Grey","colorHex":"#808080","stock":25,"price":1499},{"sku":"HM-HOD-NVY-XL","size":"XL","color":"Navy","colorHex":"#000080","stock":15,"price":1499}]'::jsonb, 60, 4.3, 178, ARRAY['60% Cotton 40% Polyester', 'Oversized Fit', 'Kangaroo Pocket', 'Drawstring Hood', 'Ribbed Cuffs', 'Machine Washable', 'Unisex', 'Fleece Lined'], true),

('Adidas Ultraboost 22', 'adidas-ultraboost-22', 'Adidas Ultraboost 22 running shoes with BOOST midsole for endless energy return. Primeknit+ upper adapts to the foot, Linear Energy Push system, and Continental rubber outsole for superior grip.', 'bf01b5fb-4d88-4687-b80a-1cfc9f94051d', 'Adidas', 16999, 22099, '[{"url":"https://images.unsplash.com/photo-1608231387042-66d1773070a5?w=800&h=800&fit=crop","alt":"Adidas Ultraboost"},{"url":"https://images.unsplash.com/photo-1587563871167-1ee9c731aefb?w=800&h=800&fit=crop","alt":"Running shoes side"},{"url":"https://images.unsplash.com/photo-1606107557195-0e29a4b5b4aa?w=800&h=800&fit=crop","alt":"Shoes on runner"}]'::jsonb, '[{"sku":"ADB-UB-BLK-8","size":"UK 8","color":"Core Black","colorHex":"#1A1A1A","stock":15,"price":16999},{"sku":"ADB-UB-WHT-9","size":"UK 9","color":"Cloud White","colorHex":"#F5F5F5","stock":12,"price":16999},{"sku":"ADB-UB-BLK-10","size":"UK 10","color":"Core Black","colorHex":"#1A1A1A","stock":10,"price":16999}]'::jsonb, 37, 4.7, 234, ARRAY['BOOST Midsole', 'Primeknit+ Upper', 'Continental Rubber', 'Linear Energy Push', 'Lace Closure', 'Weight: 310g', 'Drop: 10mm', 'Neutral Pronation'], true),

('Zara Leather Crossbody Bag', 'zara-leather-crossbody', 'Zara minimalist crossbody bag in genuine leather with adjustable strap. Compact design with magnetic flap closure, internal pocket, and antique gold hardware. Versatile for day-to-night styling.', 'bf01b5fb-4d88-4687-b80a-1cfc9f94051d', 'Zara', 3490, 4537, '[{"url":"https://images.unsplash.com/photo-1548036328-c9fa89d128fa?w=800&h=800&fit=crop","alt":"Leather Crossbody Bag"},{"url":"https://images.unsplash.com/photo-1590874103328-eac38a683ce7?w=800&h=800&fit=crop","alt":"Bag detail"},{"url":"https://images.unsplash.com/photo-1584917865442-de89df76afd3?w=800&h=800&fit=crop","alt":"Bag styled"}]'::jsonb, '[{"sku":"ZR-BAG-BLK","size":"One Size","color":"Black","colorHex":"#000000","stock":18,"price":3490},{"sku":"ZR-BAG-TAN","size":"One Size","color":"Tan","colorHex":"#D2691E","stock":14,"price":3490},{"sku":"ZR-BAG-BRG","size":"One Size","color":"Burgundy","colorHex":"#800020","stock":10,"price":3490}]'::jsonb, 42, 4.4, 96, ARRAY['Genuine Leather', 'Adjustable Strap', 'Magnetic Closure', 'Internal Pocket', 'Dimensions: 22x16x7cm', 'Gold Hardware', 'Dust Bag Included', 'Made in Spain'], true);

-- New Books (3)
INSERT INTO products (name, slug, description, category_id, brand, price, compare_at_price, images, variants, total_stock, rating_average, rating_count, tags, is_active) VALUES
('Sapiens by Yuval Noah Harari', 'sapiens-yuval-harari', 'Sapiens: A Brief History of Humankind explores how Homo sapiens came to dominate the world. From the Cognitive Revolution to the Scientific Revolution, Harari weaves biology, history, and economics into a compelling narrative.', '286610b5-e939-4cb7-9e99-57e0dce15b62', 'Vintage', 499, 649, '[{"url":"https://images.unsplash.com/photo-1589998059171-988d887df646?w=800&h=800&fit=crop","alt":"Sapiens Book"},{"url":"https://images.unsplash.com/photo-1481627834876-b7833e8f5570?w=800&h=800&fit=crop","alt":"Library reading"},{"url":"https://images.unsplash.com/photo-1516979187457-637abb4f9353?w=800&h=800&fit=crop","alt":"Book shelf"}]'::jsonb, '[{"sku":"SAP-PB","size":"Paperback","color":"Standard","colorHex":"#8B4513","stock":40,"price":499}]'::jsonb, 40, 4.7, 567, ARRAY['Author: Yuval Noah Harari', 'Pages: 464', 'Publisher: Vintage', 'Language: English', 'Genre: History/Anthropology', 'ISBN: 978-0099590088', 'Paperback', 'International Bestseller'], true),

('Deep Work by Cal Newport', 'deep-work-cal-newport', 'Deep Work by Cal Newport provides rules for focused success in a distracted world. Learn to cultivate deep focus, eliminate shallow work, and produce elite-level results in less time.', '286610b5-e939-4cb7-9e99-57e0dce15b62', 'Piatkus', 399, 519, '[{"url":"https://images.unsplash.com/photo-1519682577862-22b62b24e493?w=800&h=800&fit=crop","alt":"Deep Work Book"},{"url":"https://images.unsplash.com/photo-1434030216411-0b793f4b4173?w=800&h=800&fit=crop","alt":"Focused work"},{"url":"https://images.unsplash.com/photo-1488190211105-8b0e65b80b4e?w=800&h=800&fit=crop","alt":"Study desk"}]'::jsonb, '[{"sku":"DW-PB","size":"Paperback","color":"Standard","colorHex":"#2F4F4F","stock":35,"price":399}]'::jsonb, 35, 4.5, 312, ARRAY['Author: Cal Newport', 'Pages: 304', 'Publisher: Piatkus', 'Language: English', 'Genre: Productivity', 'ISBN: 978-0349411903', 'Paperback', 'Bestseller'], true),

('The Alchemist by Paulo Coelho', 'the-alchemist-coelho', 'The Alchemist by Paulo Coelho — a magical fable about following your dreams. Santiago, a shepherd boy, journeys from Spain to Egypt in search of treasure and discovers the true meaning of life along the way.', '286610b5-e939-4cb7-9e99-57e0dce15b62', 'HarperOne', 299, 389, '[{"url":"https://images.unsplash.com/photo-1544716278-ca5e3f4abd8c?w=800&h=800&fit=crop","alt":"The Alchemist Book"},{"url":"https://images.unsplash.com/photo-1468071174046-657d9d351dd5?w=800&h=800&fit=crop","alt":"Desert landscape"},{"url":"https://images.unsplash.com/photo-1506880018603-83d5b814b5a6?w=800&h=800&fit=crop","alt":"Reading in cafe"}]'::jsonb, '[{"sku":"ALC-PB","size":"Paperback","color":"Standard","colorHex":"#DAA520","stock":50,"price":299}]'::jsonb, 50, 4.6, 891, ARRAY['Author: Paulo Coelho', 'Pages: 197', 'Publisher: HarperOne', 'Language: English', 'Genre: Fiction/Philosophy', 'ISBN: 978-0062315007', 'Paperback', '150 Million Copies Sold'], true);

-- New Home & Garden (3)
INSERT INTO products (name, slug, description, category_id, brand, price, compare_at_price, images, variants, total_stock, rating_average, rating_count, tags, is_active) VALUES
('Prestige Iris 750W Mixer Grinder', 'prestige-iris-mixer', 'Prestige Iris 750 Watt mixer grinder with 3 stainless steel jars. Powerful motor with 3-speed control and pulse function. Super efficient blades for wet and dry grinding, chutney, and juicing.', '0e3bd9da-234a-4ecf-a729-d445ff4ba4df', 'Prestige', 3299, 4289, '[{"url":"https://images.unsplash.com/photo-1570222094114-d054a817e56b?w=800&h=800&fit=crop","alt":"Mixer Grinder"},{"url":"https://images.unsplash.com/photo-1556909114-44e3e70034e2?w=800&h=800&fit=crop","alt":"Kitchen appliance"},{"url":"https://images.unsplash.com/photo-1574269909862-7e1d70bb8078?w=800&h=800&fit=crop","alt":"Blending ingredients"}]'::jsonb, '[{"sku":"PRS-MX-WHT","size":"750W","color":"White","colorHex":"#FFFFFF","stock":22,"price":3299},{"sku":"PRS-MX-RED","size":"750W","color":"Red","colorHex":"#FF0000","stock":15,"price":3299}]'::jsonb, 37, 4.3, 234, ARRAY['750W Motor', '3 SS Jars', '3 Speed Control', 'Pulse Function', 'Overload Protection', 'Anti-Skid Feet', 'ISI Certified', 'Warranty: 2 Years'], true),

('Solimo 100% Cotton Bath Towel Set', 'solimo-bath-towel-set', 'Amazon Brand Solimo 100% cotton bath towel set of 4. Ultra-soft, highly absorbent 500 GSM terry towels. Quick-drying, lint-free, and machine washable. Perfect for daily use with vibrant colorfastness.', '0e3bd9da-234a-4ecf-a729-d445ff4ba4df', 'Solimo', 1299, 1689, '[{"url":"https://images.unsplash.com/photo-1616627561950-9f746e330187?w=800&h=800&fit=crop","alt":"Bath Towel Set"},{"url":"https://images.unsplash.com/photo-1600369672770-985fd30004eb?w=800&h=800&fit=crop","alt":"Stacked towels"},{"url":"https://images.unsplash.com/photo-1563453392212-326f5e854473?w=800&h=800&fit=crop","alt":"Towels in bathroom"}]'::jsonb, '[{"sku":"SOL-TWL-BLU","size":"Bath (140x70cm)","color":"Blue","colorHex":"#4169E1","stock":30,"price":1299},{"sku":"SOL-TWL-GRY","size":"Bath (140x70cm)","color":"Grey","colorHex":"#808080","stock":25,"price":1299},{"sku":"SOL-TWL-WHT","size":"Bath (140x70cm)","color":"White","colorHex":"#FFFFFF","stock":20,"price":1299}]'::jsonb, 75, 4.2, 456, ARRAY['100% Cotton', '500 GSM', 'Set of 4', 'Size: 140x70cm', 'Machine Washable', 'Quick Drying', 'Lint Free', 'Colorfast'], true),

('Wipro 9W LED Smart Bulb', 'wipro-smart-bulb', 'Wipro 9W LED Smart Bulb with 16 million colors and tunable white light. Works with Alexa and Google Home. Control via Wipro Smart Home app — set schedules, scenes, and groups wirelessly.', '0e3bd9da-234a-4ecf-a729-d445ff4ba4df', 'Wipro', 799, 1039, '[{"url":"https://images.unsplash.com/photo-1558618666-fcd25c85f82e?w=800&h=800&fit=crop","alt":"Smart LED Bulb"},{"url":"https://images.unsplash.com/photo-1565814329452-e1efa11a5b89?w=800&h=800&fit=crop","alt":"Smart bulb colors"},{"url":"https://images.unsplash.com/photo-1507494924047-60b8ee826ca9?w=800&h=800&fit=crop","alt":"Smart home lighting"}]'::jsonb, '[{"sku":"WPR-BLB-E27","size":"E27","color":"White","colorHex":"#FFFFFF","stock":50,"price":799},{"sku":"WPR-BLB-B22","size":"B22","color":"White","colorHex":"#FFFFFF","stock":40,"price":799}]'::jsonb, 90, 4.1, 567, ARRAY['9W (60W Equivalent)', '16 Million Colors', 'Works with Alexa', 'Works with Google Home', 'Wi-Fi Enabled', 'App Control', 'Schedule & Timer', 'Energy Efficient'], true);

-- New Sports (3)
INSERT INTO products (name, slug, description, category_id, brand, price, compare_at_price, images, variants, total_stock, rating_average, rating_count, tags, is_active) VALUES
('Decathlon Domyos 10kg Dumbbell Set', 'decathlon-dumbbell-set', 'Decathlon Domyos adjustable dumbbell set with 10kg total weight. Chrome-plated iron plates with textured grip bars. Spinlock collars for secure weight changes. Perfect for home strength training.', 'd3ffd93c-823d-4d2d-a089-1548ca261e35', 'Decathlon', 1499, 1949, '[{"url":"https://images.unsplash.com/photo-1583454110551-21f2fa2afe61?w=800&h=800&fit=crop","alt":"Dumbbell Set"},{"url":"https://images.unsplash.com/photo-1534438327276-14e5300c3a48?w=800&h=800&fit=crop","alt":"Home gym"},{"url":"https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=800&h=800&fit=crop","alt":"Weight training"}]'::jsonb, '[{"sku":"DEC-DB-10","size":"10kg Set","color":"Silver","colorHex":"#C0C0C0","stock":20,"price":1499}]'::jsonb, 20, 4.4, 189, ARRAY['Total Weight: 10kg', 'Chrome Plated Iron', 'Spinlock Collars', 'Textured Grip', 'Adjustable Weights', 'Includes Carry Case', 'Home Gym Essential', 'Warranty: 2 Years'], true),

('SG Cricket Bat - RSD Xtreme', 'sg-cricket-bat-rsd', 'SG RSD Xtreme English Willow cricket bat with thick edges and full-profile bow. Grade 3+ willow with traditional cane handle, Singapore multi-piece construction, and premium grip for power hitting.', 'd3ffd93c-823d-4d2d-a089-1548ca261e35', 'SG', 4999, 6499, '[{"url":"https://images.unsplash.com/photo-1531415074968-036ba1b575da?w=800&h=800&fit=crop","alt":"Cricket Bat"},{"url":"https://images.unsplash.com/photo-1540747913346-19e32dc3e97e?w=800&h=800&fit=crop","alt":"Cricket game"},{"url":"https://images.unsplash.com/photo-1624526267942-ab0ff8a3e972?w=800&h=800&fit=crop","alt":"Bat close-up"}]'::jsonb, '[{"sku":"SG-BAT-SH","size":"Short Handle","color":"Natural","colorHex":"#DEB887","stock":12,"price":4999},{"sku":"SG-BAT-LH","size":"Long Handle","color":"Natural","colorHex":"#DEB887","stock":8,"price":5299}]'::jsonb, 20, 4.5, 145, ARRAY['English Willow', 'Grade 3+', 'Thick Edges', 'Full Profile Bow', 'Cane Handle', 'Singapore Construction', 'Premium Grip', 'Toe Guard Included'], true),

('Puma Running Shorts - DryCell', 'puma-running-shorts', 'Puma DryCell running shorts with moisture-wicking technology for maximum comfort during workouts. Lightweight, breathable fabric with inner brief, elastic waistband, and reflective detailing for visibility.', 'd3ffd93c-823d-4d2d-a089-1548ca261e35', 'Puma', 999, 1299, '[{"url":"https://images.unsplash.com/photo-1562886877-aaaa5c16396e?w=800&h=800&fit=crop","alt":"Running Shorts"},{"url":"https://images.unsplash.com/photo-1556906781-9a412961c28c?w=800&h=800&fit=crop","alt":"Athletic shorts"},{"url":"https://images.unsplash.com/photo-1594882645126-14020914d58d?w=800&h=800&fit=crop","alt":"Running athlete"}]'::jsonb, '[{"sku":"PM-SRT-BLK-M","size":"M","color":"Black","colorHex":"#000000","stock":25,"price":999},{"sku":"PM-SRT-NVY-L","size":"L","color":"Navy","colorHex":"#000080","stock":20,"price":999},{"sku":"PM-SRT-GRY-XL","size":"XL","color":"Grey","colorHex":"#808080","stock":15,"price":999}]'::jsonb, 60, 4.3, 201, ARRAY['DryCell Technology', 'Moisture Wicking', 'Inner Brief', 'Elastic Waistband', 'Reflective Details', 'Lightweight', '100% Polyester', 'Machine Washable'], true);

-- New Beauty (3)
INSERT INTO products (name, slug, description, category_id, brand, price, compare_at_price, images, variants, total_stock, rating_average, rating_count, tags, is_active) VALUES
('The Ordinary Niacinamide 10% + Zinc 1%', 'ordinary-niacinamide-serum', 'The Ordinary Niacinamide 10% + Zinc 1% serum targets blemishes, enlarged pores, and uneven skin tone. Water-based formula with high-strength vitamins that visibly reduce skin congestion and oiliness.', 'd56fe102-8fd6-4104-848f-aeb137d7bd9f', 'The Ordinary', 590, 767, '[{"url":"https://images.unsplash.com/photo-1620916566398-39f1143ab7be?w=800&h=800&fit=crop","alt":"Niacinamide Serum"},{"url":"https://images.unsplash.com/photo-1556228578-8c89e6adf883?w=800&h=800&fit=crop","alt":"Skincare serum"},{"url":"https://images.unsplash.com/photo-1611930022073-b7a4ba5fcccd?w=800&h=800&fit=crop","alt":"Skincare routine"}]'::jsonb, '[{"sku":"TO-NIA-30","size":"30ml","color":"Standard","colorHex":"#F5F5DC","stock":45,"price":590}]'::jsonb, 45, 4.6, 678, ARRAY['Niacinamide 10%', 'Zinc PCA 1%', 'Volume: 30ml', 'For Oily/Blemish-Prone Skin', 'Cruelty Free', 'Vegan', 'Paraben Free', 'Water-Based Formula'], true),

('MAC Ruby Woo Lipstick', 'mac-ruby-woo-lipstick', 'MAC Ruby Woo — the iconic retro matte lipstick in a vivid blue-red shade. Long-wearing, non-feathering formula with intense color payoff. The most-sold lipstick shade worldwide for a classic, bold lip look.', 'd56fe102-8fd6-4104-848f-aeb137d7bd9f', 'MAC', 1950, 2535, '[{"url":"https://images.unsplash.com/photo-1586495777744-4413f21062fa?w=800&h=800&fit=crop","alt":"MAC Lipstick"},{"url":"https://images.unsplash.com/photo-1631214500115-598fc2cb8ada?w=800&h=800&fit=crop","alt":"Lipstick shade"},{"url":"https://images.unsplash.com/photo-1596462502278-27bfdc403348?w=800&h=800&fit=crop","alt":"Lipstick collection"}]'::jsonb, '[{"sku":"MAC-RW","size":"3g","color":"Ruby Woo","colorHex":"#CC0000","stock":30,"price":1950}]'::jsonb, 30, 4.8, 432, ARRAY['Finish: Retro Matte', 'Weight: 3g', 'Shade: Vivid Blue-Red', 'Long Wearing', 'Non-Feathering', 'Intense Color', 'Iconic Shade', 'Cruelty Free'], true),

('Biotique Bio Kelp Shampoo', 'biotique-bio-kelp-shampoo', 'Biotique Bio Kelp Protein Shampoo for falling hair. Enriched with natural sea kelp, peppermint oil, and neem to strengthen hair roots, reduce hair fall, and promote healthy, shiny hair growth.', 'd56fe102-8fd6-4104-848f-aeb137d7bd9f', 'Biotique', 249, 324, '[{"url":"https://images.unsplash.com/photo-1535585209827-a15fcdbc4c2d?w=800&h=800&fit=crop","alt":"Bio Kelp Shampoo"},{"url":"https://images.unsplash.com/photo-1585232004423-244e0e6904e3?w=800&h=800&fit=crop","alt":"Shampoo bottle"},{"url":"https://images.unsplash.com/photo-1522337360788-8b13dee7a37e?w=800&h=800&fit=crop","alt":"Hair care products"}]'::jsonb, '[{"sku":"BIO-SHP-190","size":"190ml","color":"Standard","colorHex":"#228B22","stock":40,"price":249},{"sku":"BIO-SHP-340","size":"340ml","color":"Standard","colorHex":"#228B22","stock":30,"price":399}]'::jsonb, 70, 4.1, 345, ARRAY['Key Ingredient: Sea Kelp', 'With Peppermint Oil', 'Anti Hair Fall', 'Paraben Free', 'SLS Free', '100% Botanical', 'For All Hair Types', 'Made in India'], true);
